8	
9	#ifndef CUDAQ_OPTIMIZER_DIALECT_QUAKE_TYPES
10	#define CUDAQ_OPTIMIZER_DIALECT_QUAKE_TYPES
11	
12	include "cudaq/Optimizer/Dialect/Quake/QuakeDialect.td"
13	include "mlir/IR/AttrTypeBase.td"
14	
15	//===----------------------------------------------------------------------===//
16	// BaseType
17	//===----------------------------------------------------------------------===//
18	
19	class QuakeType<string name, string typeMnemonic, list<Trait> traits = [],
20	        string baseCppClass = "mlir::Type">
21	    : TypeDef<QuakeDialect, name, traits, baseCppClass> {
22	  let mnemonic = typeMnemonic;
23	}
24	
25	//===----------------------------------------------------------------------===//
26	// Wire type: quantum value type
27	//===----------------------------------------------------------------------===//
28	
29	def WireType : QuakeType<"Wire", "wire"> {
30	  let summary = "a linear type for a quantum value";
31	  let description = [{
32	    A `wire` is a primitive quantum "SSA-value" that differs from a traditional
33	    SSA-value in that it can and will be modified when used in any target
34	    position. That means quantum "SSA-values" are not true SSA values. To
35	    enforce this property a `wire` type is a linear type. Therefore, `wire`
36	    values must be used exactly once. A `wire` value might be thought of as
37	    having somewhat similar properties to volatile memory. An operation that
38	    uses a `wire` is required to return a new `wire` value reflecting the
39	    updated/new state and propagating the linear type.
40	
41	    The following is a simple example of using `wire` values.
42	
43	    ```mlir
44	      // Create two wires.
45	      %q0 = ... : !quake.wire
46	      %q1 = ... : !quake.wire
47	
48	      // Apply some quantum gates.
49	      %q2:2 = quake.gate1 [%q0] %q1 : (!quake.wire, !quake.wire) ->
50	                 (!quake.wire, !quake.wire)
51	      %q3 = quake.gate2 %q2#0 : (!quake.wire) -> !quake.wire
52	
53	      // Final use of the wires.
54	      quake.sink %q3 : !quake.wire
55	      quake.wrap %q2#1 to %r0 : !quake.wire, !quake.ref
56	    ```
57	
58	    See also the description of the `ref` type.
59	  }];
60	
61	  let genStorageClass = 0;
62	}
63	
64	//===----------------------------------------------------------------------===//
65	// Control type: quantum value type
66	//===----------------------------------------------------------------------===//
67	
68	def ControlType : QuakeType<"Control", "control"> {
69	  let summary = "an SSA type for a quantum control value";
70	  let description = [{
71	    A value having type `control` is quite similar to a value of type `wire`.
72	    The distinction is that a value of type `control` must be used in a control
73	    position of a quantum operator. Using a qubit in a control position means
74	    the qubit \em{is} an SSA value. Values of type `control`, unlike values of
75	    type `wire`, can be defined once and used multiple times (in multiple
76	    control positions on distinct quantum operators) without changing value.
77	
78	    ```mlir
79	      %10 = quake.to_ctrl %0 : (!quake.wire) -> !quake.control
80	      %11 = quake.g1 [%10] %1 : (!quake.control, !quake.wire) -> !quake.wire
81	      %12 = quake.g2 [%10] %2 : (!quake.control, !quake.wire) -> !quake.wire
82	      %13 = quake.g3 [%10] %3 : (!quake.control, !quake.wire) -> !quake.wire
83	      %20 = quake.from_ctrl %10 : (!quake.control) -> !quake.wire
84	    ```
85	  }];
86	
87	  let genStorageClass = 0;
88	}
89	
90	//===----------------------------------------------------------------------===//
91	// RefType: quantum reference type
92	//===----------------------------------------------------------------------===//
93	
94	def RefType : QuakeType<"Ref", "ref"> {
95	  let summary = "a reference to a quantum wire";
96	  let description = [{
97	    A `ref` represents a reference to a value of `wire` type.  One can view the
98	    values of this type as the horizontal lines in the following quantum circuit
99	    diagram. A value of type `ref` is an SSA value with reference semantics. A
100	    quantum operator that uses a `ref` value implicitly performs an unwrap
101	    (read), modify, and wrap (write) on the "wire" value referenced.
102	
103	    ```
104	    q0 : ─────●────────── <--+
105	              │              |
106	            ┌─┴┐  ┌──┐       |
107	    q1 : ───┤  ├──┤  ├─── <--+-- `ref`s
108	            └──┘  └──┘
109	    ```
110	
111	    The following example is the quake representation of the above circuit.
112	    (gate1 and gate2 are quantum gates.)
113	
114	    ```mlir
115	      %q0 = quake.alloca : !quake.ref
116	      %q1 = quake.alloca : !quake.ref
117	      quake.gate1 [%q0] (%q1)
118	      quake.gate2 (%q1)
119	    ```
120	
121	    In the example, `gate1` has quantum memory side-effects on the reference
122	    `%q1 : !quake.ref`, which is assumed to be modified in place, similar to a
123	    volatile memory location. The next operation, `gate2`, also has quantum
124	    memory side-effects through the same reference, `%q1`. Because these
125	    operations use the same reference, they cannot be reordered relative to one
126	    another.
127	    
128	    Furthermore, `gate1` implies \em{only} a quantum memory read side-effect on
129	    the reference value `%q0`. This is because `%q0` appears in a control
130	    position in `gate1`, as indicated by the square brackets.
131	  }];
132	
133	  let genStorageClass = 0;
134	}
135	
136	//===----------------------------------------------------------------------===//
137	// VeqType: quantum reference type
138	//===----------------------------------------------------------------------===//
139	
140	def VeqType : QuakeType<"Veq", "veq"> {
141	  let summary = "an sequence of quantum references";
142	  let description = [{
143	    A value of type `veq` is a (linear) collection of values of type `ref`.
144	    These aggregates are a convenience for referring to an entire group of
145	    quantum memory references. A `veq` value is an SSA value and can be defined
146	    once and used multiple times. `ref` values in a `veq` are non-volatile, so
147	    extracting a `ref` at the same index multiple times yields copies of the
148	    same quantum memory reference.
149	  }];
150	
151	  let parameters = (ins "std::size_t":$size);
152	
153	  let hasCustomAssemblyFormat = 1;
154	  
155	  let extraClassDeclaration = [{
156	    static constexpr std::size_t kDynamicSize =
157	      std::numeric_limits<std::size_t>::max();
158	
159	    bool hasSpecifiedSize() const { return getSize() != kDynamicSize; }
160	    bool hasNonZeroSpecifiedSize() const {
161	      return hasSpecifiedSize() && getSize();
162	    }
163	    static VeqType getUnsized(mlir::MLIRContext *ctx) {
164	      return VeqType::get(ctx, kDynamicSize);
165	    }
166	  }];
167	}
168	
169	//===----------------------------------------------------------------------===//
170	// StruqType: quantum reference type; product of veq and ref types.
171	//===----------------------------------------------------------------------===//
172	
173	def StruqType : QuakeType<"Struq", "struq"> {
174	  let summary = "a flattened product type of quantum references";
175	  let description = [{
176	    This type allows one to group veqs of quantum references together in a
177	    single product type.
178	
179	    To support Python, a struq type can be assigned a name. This allows the
180	    python bridge to perform dictionary based lookups on member field names.
181	  }];
182	
183	  let parameters = (ins
184	    "mlir::StringAttr":$name,
185	    // members must be NonStruqRefType.
186	    ArrayRefParameter<"mlir::Type">:$members
187	  );
188	
189	  let hasCustomAssemblyFormat = 1;
190	
191	  let extraClassDeclaration = [{
192	    std::size_t getNumMembers() const { return getMembers().size(); }
193	    std::optional<std::size_t> getArity() const;
194	    bool hasSpecifiedSize() const;
195	    bool hasNonZeroSpecifiedSize() const {
196	      auto arity = getArity();
197	      return arity && *arity;
198	    }
199	  }];
200	
201	  let builders = [
202	    TypeBuilder<(ins CArg<"llvm::ArrayRef<mlir::Type>">:$members), [{
203	      return $_get($_ctxt, mlir::StringAttr{}, members);
204	    }]>,
205	    TypeBuilder<(ins CArg<"llvm::StringRef">:$name,
206	                     CArg<"llvm::ArrayRef<mlir::Type>">:$members), [{
207	      return $_get($_ctxt, mlir::StringAttr::get($_ctxt, name), members);
208	    }]>
209	  ];
210	}
211	
212	def CableType : QuakeType<"Cable", "cable"> {
213	  let summary = "a sequence type for an aggregate of wires";
214	  let description = [{
215	    This is the type of an aggregate of wire types. It is simply syntactic
216	    sugar that allows a group of wires to be passed around as a single cable
217	    value.
218	
219	    There is a mapping from any constant sized quantum reference type to a cable
220	    type. A `!quake.ref` can map to a `!quake.cable<1>`. A `!quake.veq<n>` can
221	    be mapped to a `!quake.cable<n>` retaining relative position and indices. A
222	    `!quake.struq<{m0, ...}>` can be mapped left-to-right in member order. Each
223	    member must be a `!quake.ref` or a `!quake.veq<n>` and will be mapped as
224	    above with each member concatenating to the previous member.
225	  }];
226	
227	  let parameters = (ins "std::uint64_t":$size);
228	
229	  let assemblyFormat = "`<` $size `>`";
230	}
231	
232	//===----------------------------------------------------------------------===//
233	// MeasureType: classical data type
234	//===----------------------------------------------------------------------===//
235	
236	def MeasureType : QuakeType<"Measure", "measure"> {
237	  let summary = "a classical result produced by a quantum measurement";
238	  let description = [{
239	    A quantum measurement captures the state of a qubit and returns a classical
240	    regular (not linear) SSA value from the measurement. Note that, a value of
241	    type `measure` is not volatile. Depending on the target system this value
242	    may have two or more logical states. Typically, a value of type `measure`
243	    will be discriminated into a binary bit (or small integer).
244	
245	    ```mlir
246	      %m = quake.mz %0 : (!quake.ref) -> !quake.measure
247	      quake.dealloc %0 : !quake.ref
248	    ```
249	  }];
250	
251	  let genStorageClass = 0;
252	}
253	
254	//===----------------------------------------------------------------------===//
255	// StateType
256	//===----------------------------------------------------------------------===//
257	
258	def quake_StateType : QuakeType<"State", "state"> {
259	  let summary = "Proxy for the cudaq::state class.";
260	  let description = [{
261	    The cudaq::state class is an abstraction for any data that may be used to
262	    describe the initial state of a set of qubits. It would typically be used
263	    in a simulation environment.
264	
265	    The CUDA-Q runtime will implement an ABI of intrinsic functions for the
266	    compiler generated code to interface with this information in a generic
267	    manner.
268	
269	    There are no legal operations in Quake/CC on a value of type `!quake.state`.
270	    Only pointers to such values should exist in the IR for the purposes of
271	    passing references to state objects to runtime functions at codegen.
272	  }];
273	  let genStorageClass = 0;
274	}
275	
276	def AnyQTypeLike : TypeConstraint<Or<[WireType.predicate, VeqType.predicate,
277	        ControlType.predicate, RefType.predicate, StruqType.predicate]>,
278	        "quake quantum types">;
279	def AnyQType : Type<AnyQTypeLike.predicate, "quantum type">;
280	def AnyQTargetTypeLike : TypeConstraint<Or<[WireType.predicate,
281	        VeqType.predicate, RefType.predicate]>, "quake quantum target types">;
282	def AnyQTargetType : Type<AnyQTargetTypeLike.predicate, "quantum target type">;
283	def AnyRefTypeLike : TypeConstraint<Or<[VeqType.predicate, StruqType.predicate,
284	        RefType.predicate]>, "quake quantum reference types">;
285	def AnyRefType : Type<AnyRefTypeLike.predicate, "quantum reference type">;
286	def NonStruqRefTypeLike : TypeConstraint<Or<[VeqType.predicate,
287	        RefType.predicate]>, "non-struct quake quantum reference types">;
288	def NonStruqRefType : Type<NonStruqRefTypeLike.predicate,
289	        "non-struct quantum reference type">;
290	def AnyQValueTypeLike : TypeConstraint<Or<[WireType.predicate,
291	        ControlType.predicate, CableType.predicate]>,
292	        "quake quantum value types">;
293	def AnyQValueType : Type<AnyQValueTypeLike.predicate, "any quantum value type">;
294	def AnyQLinearTypeLike : TypeConstraint<Or<[WireType.predicate,
295	        CableType.predicate]>, "quake linear quantum value types">;
296	def AnyQLinearType : Type<AnyQLinearTypeLike.predicate,
297	        "any linear quantum value type">;
298	
299	#endif // CUDAQ_OPTIMIZER_DIALECT_QUAKE_TYPES
